import React from "react";
import { BrowserRouter, Routes, Route, NavLink } from "react-router-dom";
import Dashboard from "./pages/Dashboard";
import DoctorsPage from "./pages/DoctorsPage";
import AppointmentsPage from "./pages/AppointmentsPage";

const NAV_ITEMS = [
  { to: "/", label: "Dashboard", icon: "⬡" },
  { to: "/doctors", label: "Doctors", icon: "♤" },
  { to: "/appointments", label: "Appointments", icon: "◈" },
];

function Layout() {
  return (
    <div style={{ display: "flex", minHeight: "100vh", background: "#020810" }}>
      {/* Sidebar */}
      <nav style={{
        width: 220,
        background: "#030d18",
        borderRight: "1px solid #0d3a5c",
        display: "flex",
        flexDirection: "column",
        padding: "28px 0",
        position: "fixed",
        height: "100vh",
        zIndex: 100,
      }}>
        {/* Logo */}
        <div style={{ padding: "0 24px 32px" }}>
          <div style={{
            fontFamily: "'Syne', sans-serif",
            fontWeight: 800,
            fontSize: 18,
            color: "#00bcd4",
            letterSpacing: -0.5,
          }}>
            MediBook
          </div>
          <div style={{ fontFamily: "'DM Mono', monospace", fontSize: 10, color: "#263238", letterSpacing: 2, marginTop: 2 }}>
            HEALTHCARE SYSTEM
          </div>
        </div>

        {/* Nav Links */}
        <div style={{ display: "flex", flexDirection: "column", gap: 4, padding: "0 12px" }}>
          {NAV_ITEMS.map((item) => (
            <NavLink
              key={item.to}
              to={item.to}
              end={item.to === "/"}
              style={({ isActive }) => ({
                display: "flex",
                alignItems: "center",
                gap: 12,
                padding: "11px 14px",
                borderRadius: 9,
                textDecoration: "none",
                fontFamily: "'DM Mono', monospace",
                fontSize: 13,
                color: isActive ? "#00e5ff" : "#546e7a",
                background: isActive ? "rgba(0,188,212,0.08)" : "transparent",
                borderLeft: isActive ? "2px solid #00bcd4" : "2px solid transparent",
                transition: "all 0.15s",
              })}
            >
              <span style={{ fontSize: 16 }}>{item.icon}</span>
              {item.label}
            </NavLink>
          ))}
        </div>

        {/* Footer */}
        <div style={{ marginTop: "auto", padding: "0 24px" }}>
          <div style={{ borderTop: "1px solid #0d2e48", paddingTop: 20 }}>
            <p style={{ fontFamily: "'DM Mono', monospace", fontSize: 10, color: "#1a3a4a", margin: 0 }}>
              v1.0.0 · OPC 2026
            </p>
          </div>
        </div>
      </nav>

      {/* Main content */}
      <main style={{ marginLeft: 220, flex: 1, padding: "40px 48px", maxWidth: "calc(100vw - 220px)" }}>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/doctors" element={<DoctorsPage />} />
          <Route path="/appointments" element={<AppointmentsPage />} />
        </Routes>
      </main>
    </div>
  );
}

export default function App() {
  return (
    <BrowserRouter>
      <Layout />
    </BrowserRouter>
  );
}
